import React, { useState, useEffect, useCallback } from 'react';
import Sidebar from './components/Sidebar';
import Dashboard from './components/Dashboard';
import NewClaim from './components/NewClaim';
import MyClaims from './components/MyClaims';
import SupervisorQueue from './components/SupervisorQueue';
import HRSQueue from './components/HRSQueue';
import { ECMQueue, DMCQueue } from './components/Queues';
import Tariffs from './components/Tariffs';
import Reports from './components/Reports';
import { Toast } from './components/Shared';
import { SAMPLE_CLAIMS } from './data/constants';

export default function App() {
  const [page, setPage] = useState('dashboard');
  const [claims, setClaims] = useState(SAMPLE_CLAIMS);
  const [toastMsg, setToastMsg] = useState('');
  const [toastVisible, setToastVisible] = useState(false);

  const toast = useCallback((msg) => {
    setToastMsg(msg);
    setToastVisible(true);
    setTimeout(() => setToastVisible(false), 3200);
  }, []);

  function updateStatus(ref, newStatus, extra = {}) {
    setClaims(prev => prev.map(c => c.ref === ref ? { ...c, status: newStatus, ...extra } : c));
  }

  const badges = {
    my:  claims.filter(c => c.name.startsWith('DLAMINI')).length,
    sup: claims.filter(c => c.status === 'pending').length,
    hrs: claims.filter(c => c.status === 'approved').length,
    ecm: claims.filter(c => c.status === 'ecm').length,
  };

  function onNav(id) {
    setPage(id);
  }

  const content = () => {
    switch (page) {
      case 'dashboard':
        return <Dashboard claims={claims} onNav={onNav} />;
      case 'new-claim':
        return <NewClaim
          onSubmit={claim => { setClaims(prev => [claim, ...prev]); setPage('my-claims'); }}
          onSaveDraft={() => toast('Draft saved')}
          toast={toast}
        />;
      case 'my-claims':
        return <MyClaims claims={claims} onNav={onNav} toast={toast} />;
      case 'supervisor':
        return <SupervisorQueue
          claims={claims}
          onApprove={ref => { updateStatus(ref, 'approved'); toast(ref + ' approved — sent to HRS Payroll'); }}
          onReject={ref => { updateStatus(ref, 'rejected'); toast(ref + ' rejected — official notified'); }}
        />;
      case 'hrs':
        return <HRSQueue
          claims={claims}
          onCapture={ref => {
            const mandate = 'MAN-2026-0' + (Math.floor(Math.random() * 90) + 10);
            updateStatus(ref, 'ecm', { mandate });
            toast(ref + ' captured on Persal — mandate ' + mandate + ' uploaded to ECM');
          }}
          onReject={ref => { updateStatus(ref, 'rejected'); toast(ref + ' rejected — returned to official'); }}
        />;
      case 'ecm':
        return <ECMQueue
          claims={claims}
          onRoute={ref => { updateStatus(ref, 'routed'); toast(ref + ' mandate routed to DMC Payroll Team Leader'); }}
        />;
      case 'dmc':
        return <DMCQueue
          claims={claims}
          onPaid={ref => { updateStatus(ref, 'paid'); toast(ref + ' successfully paid — Persal verification confirmed ✓'); }}
        />;
      case 'tariffs':
        return <Tariffs />;
      case 'reports':
        return <Reports claims={claims} toast={toast} />;
      default:
        return <Dashboard claims={claims} onNav={onNav} />;
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)' }}>
      <Sidebar active={page} onNav={onNav} badges={badges} />
      <main style={{ marginLeft: 'var(--sidebar-w)', padding: '1.5rem 2rem', minHeight: '100vh' }}>
        {content()}
      </main>
      <Toast message={toastMsg} visible={toastVisible} />
    </div>
  );
}
